INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Lead with the language, tool, or context. Keep it to one sentence. Be specific enough to be searchable later."},"content":{"tips":"Keep it short. A code snippet plus one paragraph of explanation is ideal. This is a snippet, not an article."},"formatting":["Code blocks: the primary format for snippets and commands","Bullet lists: quick alternatives or gotchas","Bold: highlight the key takeaway in one sentence","Links: reference docs or source material"],"avoid":["Long-form essays (keep snippets under 500 words)","Vague summaries like \"Learned about CSS\"","Missing code examples when describing a technique","Repeating the keySummary as the first line of content"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":120},"content":{"min":1,"max":2000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

